head.script:
scwin.appDt   = "";     //신청일자
scwin.busiNm  = "";     //회사명
scwin.admitYn = "";     //조회

//-------------------------------------------------------------------------
// 화면 로딩
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    scwin.appDt	  = $c.util.isEmpty($c.data.getParameter("appDt"))?     "" : $c.data.getParameter("appDt");         //신청일자
	scwin.busiNm  = $c.util.isEmpty($c.data.getParameter("busiNm"))?    "" : $c.data.getParameter("busiNm");        //회사명
	scwin.admitYn = $c.util.isEmpty($c.data.getParameter("admitYn"))?   "" : $c.data.getParameter("admitYn");       //조회
    scwin.prevRow = 0;
	scwin.CNST_MBR_CLS_MB = "05";	                                                                                //MB차주

	//공통코드 조회
	const codeOptions = [
		{ grpCd : "TN001", compID : "acb_searchMbrId,gr_master:mbrClsCd"},
        { grpCd : "TN002", compID : "lc_privGrpId"}
	];
	$c.data.setCommonCode(codeOptions, scwin.callBackSetCommonCode);

	const comboOptions = [
        {
            method : "getLuxeComboData", 
            param1 : "WorkImplementEBC", 
            param2 : "retriveLobran2CodeList",
            param3 : ["1"],
            compID : "acb_lobranCd" 
        }
    ];
    $c.data.setGauceUtil(comboOptions, function() {
        $c.gus.cfTurnCreateFlag(true);
        //$c.gus.cfInitHidVal([ed_clntNo, ed_clntCrn]);
        //scwin.f_setDefaultData();
        scwin.f_contentsDisable();

        if(!$c.gus.cfIsNull(scwin.busiNm)) { 
            ed_searchBusiNm.setValue(scwin.busiNm); 
        }

        if(!$c.gus.cfIsNull(scwin.admitYn)) {
            acb_searchAdmitYn.setValue(scwin.admitYn);
            scwin.f_retrieve();
        }
    });    
};

//-------------------------------------------------------------------------
// UDC 로딩
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    scwin.curDate = $c.date.getServerDateTime();
    udc_fromToCalendar.setInitDate(scwin.curDate, scwin.curDate);

    //acb_searchAdmitYn.setSelectedIndex(1);

    if(!$c.gus.cfIsNull(scwin.appDt)) { 
        ed_startDt.setValue(scwin.appDt); 
        ed_endDt.setValue(scwin.appDt); 
    }
    $c.data.setPopupTitle("회원승인");
}

//-------------------------------------------------------------------------
// 항목 Disable 초기화
//-------------------------------------------------------------------------
scwin.f_contentsDisable = function() {
    $c.gus.cfDisableObjects([tbl_mbrInfo, tbl_mbrDetailInfo, tbl_vehclInf, tbl_confirm]);
}

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_retrieve = async function() {
    let chkVal = await $c.gus.cfValidate([tbl_search]);
    if(!chkVal) return;

    if(!$c.gus.cfIsAfterDate(ed_startDt.getValue(), ed_endDt.getValue())) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        ed_startDt.Focus();
        return;
    }

    $c.sbm.execute(sbm_retrieve);
}

//-------------------------------------------------------------------------
// 회원정보-거래처 확인
//-------------------------------------------------------------------------
scwin.f_checkMbrClntLnkYn = function(clntNo) {

    if($c.gus.cfIsNull(clntNo)) return;

    dma_comSearch.set("sysCd", "MemberEBC");
    dma_comSearch.set("queryId", "checkMbrClntLnkYn");
    dma_comSearch.set("param1", clntNo);

    $c.sbm.execute(sbm_comSearch).then(function(e) {
        if (e.responseJSON.resultDataSet[0].Code < 0) return;

        ds_clnt.setJSON(e.responseJSON.GAUCE);
        dma_comSearch.setEmptyValue();

        if(ds_clnt.getTotalRow() != 0) {
            $c.gus.cfAlertMsg("회원ID [" + ds_clnt.getTotalRow(0, 'col1') + "]에 이미 연결된 거래처입니다.");
            $c.gus.cfInitObjects([ed_clntNo, ed_clntNm, ed_clntCrn]);
            ed_clntCrn.setValue("");
            ed_clntNo.focus();
        }
    });

}

//-------------------------------------------------------------------------
// 거래처팝업
//-------------------------------------------------------------------------
scwin.f_openClntPopUp = function(pWinCloseTF) {
    if (pWinCloseTF == 'T' && $c.gus.cfCanOpenPopup(ed_clntNo, ed_clntNm) == false) {
        if(ed_clntNo.getValue() == "") $c.gus.cfInitObjects(tbl_confirm);
        scwin.f_setClntBtnTitle();
        return;
    }

    udc_clntNo.cfCommonPopUp(     scwin.callBackClntList
                                , ed_clntNo.getValue()
                                , ed_clntNm.getValue()
                                , pWinCloseTF
                                , null
                                , null
                                , null
                                , null
                                , null
                                , null
                                , null
                                , null
                                , null
                                , null
                                , "F"
                                , "거래처,거래처코드/명" );    
}

scwin.callBackClntList = function(rtnList) {

    if(rtnList != null && rtnList[0] != "N/A") {

        if($c.gus.cfIsNull(rtnList[4])) {
            ed_clntCrn.setDisplayFormat("");
        } else {
            switch (rtnList[4].length) {
                case 10 : ed_clntCrn.setDisplayFormat("###-##-#####"); break;
                case 13 : ed_clntCrn.setDisplayFormat("######-#######"); break;
                default : ed_clntCrn.setDisplayFormat("");
            }
        }

        $c.gus.cfSetReturnValue(rtnList, ed_clntNo, ed_clntNm, ["", "", ed_clntCrn]);

        scwin.f_checkMbrClntLnkYn(ed_clntNo.getValue());
        scwin.f_setClntBtnTitle();
    } else {
        if (ed_clntNo.getValue() != "") {
            scwin.f_checkMbrClntLnkYn(ed_clntNo.getValue());
        }
        ed_clntCrn.setValue("");
    }

}

//-------------------------------------------------------------------------
// 거래처팝업(사업자등록)
//-------------------------------------------------------------------------
scwin.f_openClntCrnPopUp = function(pWinCloseTF) {
    if (pWinCloseTF == 'T' && $c.gus.cfCanOpenPopup(ed_clntCrn, ed_clntNm) == false) {
        if(ed_clntCrn.getValue() == "") $c.gus.cfInitObjects(tbl_confirm);
        scwin.f_setClntBtnTitle();
        return;
    }

    udc_clntCrn.cfCommonPopUp(    scwin.callBackClntInfo
                                , ed_clntCrn.getValue()
                                , ""
                                , pWinCloseTF
                                , null
                                , null
                                , null
                                , null
                                , null
                                , null
                                , null
                                , null
                                , null
                                , null
                                , "F"
                                , "거래처사업자(주민)번호팝업, 사업자(주민)번호");    
}

scwin.callBackClntInfo = function(rtnList) {

    if(rtnList != null && rtnList[0] != "N/A") {
        if($c.gus.cfIsNull(rtnList[0])) {
            ed_clntCrn.setDisplayFormat("");
        } else {
            switch (rtnList[0].length) {
                case 10 : ed_clntCrn.setDisplayFormat("###-##-#####"); break;
                case 13 : ed_clntCrn.setDisplayFormat("######-#######"); break;
                default : ed_clntCrn.setDisplayFormat("");
            }
        }

        $c.gus.cfSetReturnValue(rtnList, ed_clntCrn, ed_clntNm, [ed_clntNo]);
        scwin.f_checkMbrClntLnkYn(ed_clntCrn.getValue());
        scwin.f_setClntBtnTitle();
    } else {
        if (ed_clntCrn.getValue() == "") {
            ed_clntNo.setValue("");
            ed_clntNm.setValue("");
        }else {
            var curRow = ds_master.getRowPosition() == "" ? 0 : ds_master.getRowPosition();
            if (ed_clntCrn.getValue() == ds_master.getCellData(curRow, "crn")) {
                ds_master.modifyRowStatus(curRow, "R");
            }
        }
    }
}

//-------------------------------------------------------------------------
// 거래처등록
//-------------------------------------------------------------------------
scwin.f_openClntRegYnPopup = function() {
    var data = {
          clntNo : ed_clntNo.getValue()
        , mode : $c.gus.cfIsNull(ed_clntNo.getValue())? "convert" : "admitYn"
        , mbrId : ed_mbrId.getValue()
    }

    var opts = {
          id : "tn_101_01_06b"
        , popupName : "거래처등록"
        , modal : true
        , type : "browserPopup"  
        , title : "거래처등록" 
        , width : 1600
        , height : 900
        , scroll : true
    };

    var rtnList = $c.win.openPopup("/ui/tn/cs/clntmgnt/tn_101_01_06b.xml", opts, data);
    if(rtnList != null) {
        $c.gus.cfSetValue(ed_clntNo, rtnList.clntNo);
        $c.gus.cfSetValue(ed_clntNm, rtnList.clntNm);
        if(rtnList.crn) {
            switch (rtnList.crn.trim().length) {
                case 10 : ed_clntCrn.setDisplayFormatter("###-##-#####"); break;
                case 13 : ed_clntCrn.setDisplayFormatter("######-#######"); break;
                default : ed_clntCrn.setDisplayFormatter("");
            }
        }
        $c.gus.cfSetValue(ed_clntCrn, rtnList.crn);
    }

    scwin.f_setClntBtnTitle();
    $c.gus.cfPrepareObjectHidVal(ds_master, ds_master.getRowPosition(), ["clntNo", "clntNm", "clntCrn"], [ed_clntNo, ed_clntNm, ed_clntCrn]);
}

//-------------------------------------------------------------------------
// 회원 가입 등록
//-------------------------------------------------------------------------
scwin.f_save = async function() {
    let chkVal = await scwin.f_validate();
    if(!chkVal)  return;

    //번호확인
    /*if(scwin.f_chkPhone()){
        return;
    }*/

    let conf = await $c.win.confirm($c.data.getMessage(MSG_CM_CRM_001));
    if(conf) {
        $c.sbm.execute(sbm_save);
    }
}

//-------------------------------------------------------------------------
// validate check
//-------------------------------------------------------------------------
scwin.f_validate = async function() {
    if(!$c.data.isModified(ds_master)) {
        await  $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["회원승인신청현황"]); 
        return false;
    }

    var json = ds_master.getUpdatedIndex();

    for(var row=0; row < json.length; row++) {
        var i =  json[row];

        //if(ds_master.getRowStatus(i) == "R" || ds_master.getRowStatus(i) == "D") continue;

        if ($c.gus.cfIsNull(ds_master.getCellData(i, "clntNo"))) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["거래처번호"]);

            return false;
        }

        if (ds_master.getCellData(i, "crn").replace("-", "").replace("-", "").trim() != ds_master.getCellData(i, "clntCrn")) {
            await $c.gus.cfAlertMsg("회원정보와 거래처정보의 사업자번호가 일치하지 않습니다");
            await $c.win.alert("crn : "    +ds_master.getCellData(i, "crn").replace("-", "").replace("-", "").trim());
            await $c.win.alert("clntCrn : "+ds_master.getCellData(i, "clntCrn"));

            return false;
        }

        if (chk_admitYn.getValue() == "1" && $c.gus.cfIsNull(ds_master.getCellData(i, "privGrpId"))) {
            await $c.gus.cfAlertMsg("권한그룹을 선택하십시오.");

            return false;
        }
    }

    return true;
}

//-------------------------------------------------------------------------
// 전화번호 check
//-------------------------------------------------------------------------
scwin.f_chkPhone = async function() {
    var rtnVal = false;

    for(var i=0; i<ds_master.getTotalRow(); i++) { 
        if(ds_master.getRowStatus(i) == "C" || ds_master.getRowStatus(i) == "U") {
            var mpChk = scwin.f_phoneChkSave(ds_master.getCellData(i, "mpNo"), "휴대폰");
            if(mpChk){
                rtnVal = true;
                ds_master.setRowPosition(i);
                break;
            }

            var pdaChk = scwin.f_phoneChkSave(ds_master.getCellData(i, "pdaNo"), "PDA");
            if(pdaChk){
                rtnVal = true;
                ds_master.setRowPosition(i);
                break;
            }
        }
    }

    return rtnVal;
}

scwin.f_phoneChkSave = function(num, str) {   
    var rtnChk = false;
    if(num=="") return false;

    var phonestr = /^0\d{1,2}-\d{3,4}-\d{4}$/; 

    if(num != "") {
        /* 20080916
        if (!num.match(phonestr))
        {
            alert(str+"번호 형식이 올바르지 않거나 '-'를 생략하셨습니다.");
            rtnChk = true;       
            return rtnChk;         
        }        


        var str = num.substr(1,2) 

        if (!(str == "10" || str == "11" || str == "13" || str == "16" || str == "17" || str == "18" || str == "19" || str == "2-" || str == "31" || str == "32" || str == "33" || str == "41"|| str =="42" || str == "43" || str == "51" || str == "52" || str == "53"|| str == "54" || str =="55" || str =="61" || str =="62" || str =="63"  || str =="64")) {
            alert("지역 번호를 정확하게 입력하세요.");
            rtnChk = true;
            return rtnChk;
        }
        */
    }

    return rtnChk;
}

//-------------------------------------------------------------------------
// 행삭제
//-------------------------------------------------------------------------
scwin.f_deleteRow = function() {
    if(ds_master.getRowStatus(ds_master.getRowPosition()) == "R" && ds_master.getCellData(ds_master.getRowPosition(), "admitYn") == "1") {
        $c.gus.cfAlertMsg("승인된 회원은 삭세할 수 없습니다.");
        return false;
    }
    var rowidx = ds_master.getRowPosition();
    ds_master.deleteRow(rowidx);
    gr_master.setFocusedCell(rowidx, 0);
    $c.gus.cfPrepareObjectHidVal(ds_master, ds_master.getRowPosition(), ["clntNo", "clntNm", "clntCrn"], [ed_clntNo, ed_clntNm, ed_clntCrn]);
    scwin.f_setClntBtnTitle();
}

//-------------------------------------------------------------------------
// 행취소
//-------------------------------------------------------------------------
scwin.f_cancelRow = function() {
    ds_master.undoRow(ds_master.getRowPosition());
    $c.gus.cfPrepareObjectHidVal(ds_master, ds_master.getRowPosition(), ["clntNo", "clntNm", "clntCrn"], [ed_clntNo, ed_clntNm, ed_clntCrn]);
    scwin.f_setClntBtnTitle();
}

scwin.isMB = function(row) {
    return (ds_master.getCellData(row, "mbrClsCd") == scwin.CNST_MBR_CLS_MB);
}

//-------------------------------------------------------------------------
// 버튼 값 설정
//-------------------------------------------------------------------------
scwin.f_setClntBtnTitle = function() {
    btn_clntReg.setLabel($c.gus.cfIsNull(ed_clntNo.getValue())? "거래처등록" : "거래처조회");
}

//-------------------------------------------------------------------------
// Object enable/disbale
//-------------------------------------------------------------------------
scwin.f_toggleObj = function(mode, obj) {
    if ($c.gus.cfIsNull(obj)) return;
    (mode==true) ? $c.gus.cfEnableObjects(obj) : $c.gus.cfDisableObjects(obj);
}

/* ----------------------------------------------------------------------------
  T R A N S A C T I O N   C O M P O N E N T S   D E C L A R A T I O N
------------------------------------------------------------------------------*/
//조회 완료
scwin.sbm_retrieve_submitdone = function(e) {
    console.log("scwin.sbm_retrieve_submitdone");
	if (e.responseJSON.resultDataSet[0].Code < 0) return; 

    var rowCnt = ds_master.getTotalRow();
	spn_totalRow.setValue(rowCnt);

    if(rowCnt == 0) {
	    $c.gus.cfAlertMsg(MSG_CM_WRN_002);
		return;
	} else {
        gr_master.setFocusedCell(0, 0);
        ds_master.setRowJSON(0);
    }

    $c.gus.cfDisableObjects([tbl_mbrInfo, tbl_mbrDetailInfo, tbl_vehclInf, ed_clntNm, ica_admitDt]);
	scwin.f_toggleObj((acb_searchAdmitYn.getValue() == "0"), [ed_clntNo, btn_clntNo, ed_clntCrn, btn_clntCrn, btn_clntReg, chk_admitYn]);
	scwin.f_toggleObj((acb_searchAdmitYn.getValue() == "0"), [btn_deleteRow, btn_cancelRow, btn_save]);

	$c.gus.cfSetHiddenValue(ed_clntNo , ed_clntNo.getValue());
	$c.gus.cfSetHiddenValue(ed_clntCrn, ed_clntCrn.getValue());
	$c.gus.cfGoPrevPosition(gr_master, scwin.prevRow);

    //승인버튼 타이틀 변경
    if (acb_searchAdmitYn.getValue() == "0") {      //미승인
        btn_clntReg.setLabel("거래처등록");
    }else {                                         //승인
        btn_clntReg.setDisabled(false);
        btn_clntReg.setLabel("거래처조회");
        btn_clntReg.setDisabled(true);
    }

};

//저장 완료
scwin.sbm_save_submitdone = function (e) {
    console.log("scwin.sbm_save_submitdone");
	if (e.responseJSON.resultDataSet[0].Code < 0) return;

    $c.gus.cfAlertMsg(MSG_CM_INF_001);
    scwin.f_retrieve();
};

/* ----------------------------------------------------------------------------
  C O M P O N E N T' S   E V E N T S  
-----------------------------------------------------------------------------*/
//조회 버튼
scwin.btn_search_onclick = function (e) {
    $c.sbm.execute(sbm_retrieve);
};

//거래처 찾기 버튼
scwin.udc_clntNo_onclickEvent = function (e) {
    scwin.f_openClntPopUp('F');
};

scwin.udc_clntNo_onblurCodeEvent = function (e) {
    scwin.f_openClntPopUp('T');
};

//거래처사업자번호 찾기 버튼
scwin.udc_clntCrn_onclickEvent = function (e) {
    scwin.f_openClntCrnPopUp('F');
};

scwin.udc_clntCrn_onblurCodeEvent = function (e) {
    scwin.f_openClntCrnPopUp('T');
};

//거래처 등록 버튼
scwin.btn_clntReg_onclick = function (e) {
    scwin.f_openClntRegYnPopup();
};

//승인여부 값 변경 > 날짜 설정 및 권한 활성화
scwin.chk_admitYn_onviewchange = function (info) {

    if(info.checked==true) {
        ica_admitDt.setValue($c.date.getServerDateTime());
        lc_privGrpId.setDisabled(false);
    } else {
        ica_admitDt.setValue("");
        lc_privGrpId.setDisabled(true);
    }
};

//저장 버튼
scwin.btn_save_onclick = function (e) {
    scwin.f_save();
};

//그리드 row 변경
scwin.gr_master_onrowindexchange = function (rowIndex, oldRow) {
    scwin.f_toggleObj((scwin.isMB(rowIndex) && acb_searchAdmitYn.getValue() == "0"), [chk_lbsYn, ed_pdaNo]);
	scwin.f_toggleObj((acb_searchAdmitYn.getValue() == "0" && chk_admitYn.getValue()== "1"), [lc_privGrpId]);
	scwin.f_toggleObj((ds_master.getRowStatus(rowIndex) != "D" && ds_master.getCellData(rowIndex, "admitYn") == "0"), [ed_clntNo, btn_clntNo, ed_clntCrn, btn_clntCrn, btn_clntReg, chk_admitYn]);
	scwin.f_setClntBtnTitle();

    //권한 그룹 콤보값 셋팅
    lc_privGrpId.setValue(ds_master.getCellData(rowIndex, "privGrpId"));   

	//$c.gus.cfPrepareObjectHidVal(this, rowIndex, ["clntNo", "clntNm", "clntCrn"], [ed_clntNo, ed_clntNm, ed_clntCrn]);
};
scwin.chk_admitYn_onchange = function (info) {

};

scwin.ds_master_oncelldatachange = function (info) {
    if(info.colID == "admitYn"){

        if(info.newValue == ""){
            ds_master.setCellData(info.rowIndex, info.colID, "0");
        }
    }
};


//권한그룹 onViewChange
scwin.lc_privGrpId_onviewchange = function (info) {
    var curRow = ds_master.getRowPosition() == "" ? 0 : ds_master.getRowPosition();

    ds_master.setCellData(curRow, "privGrpId", lc_privGrpId.getValue());
};
